 * Handshake: { session_config, prompt: sessionConfig.optimized_prompt, history: [] }
 *
 * WS does not stream Perplexity audit in v2; audit is merged server-side before synthesis.
 * Perplexity seat accent: #20808D (True Turquoise — brand); see `constants/modelColors.js`.
 *
 * Figma frame: 03-Session-View
 */

import React, { useCallback, useEffect, useMemo, useRef, useState } from "react";
import { MODEL_HEX } from "../constants/modelColors";
import ModelBubble from "./common/ModelBubble";
import SynthesisPanel from "./SynthesisPanel";
import TakeFurther from "./TakeFurther";

const DEFAULT_HTTP = "http://localhost:8000";

/** Round 1 seat order for export fallbacks — live UI order follows `r1Order` (first token arrival). */
const R1_SENDERS = ["Gemini", "GPT", "Claude"];

/** Browser WebSocket has no configurable open timeout; guard hung connects. */
const WS_CONNECT_TIMEOUT_MS = 120_000;

/** App-level keep-alive (some proxies idle-timeout unidirectional streams). */
const WS_KEEPALIVE_INTERVAL_MS = 30_000;

function wsUrlFromApiBase() {
  const base = process.env.REACT_APP_API_URL || DEFAULT_HTTP;
  try {
    const u = new URL(base);
    u.protocol = u.protocol === "https:" ? "wss:" : "ws:";
    u.pathname = "/ws/session";
    u.search = "";
    u.hash = "";
    return u.toString();
  } catch {
    return "ws://localhost:8000/ws/session";
  }
}

/** @typedef {'gemini_r1' | 'gpt_r1' | 'claude_r1' | 'synthesis' | 'idle'} StreamPhase */

function timestamp() {
  return new Date().toLocaleTimeString("en-GB", { hour: "2-digit", minute: "2-digit", second: "2-digit" });
}

function r1Body(sender, claudeR1, geminiR1, gptR1) {
  if (sender === "Gemini") return geminiR1;
  if (sender === "GPT") return gptR1;
  return claudeR1;
}

/** Merge arrival order with any non-empty models not yet listed (e.g. partial export). */
function mergedR1Order(r1Order, claudeR1, geminiR1, gptR1) {
  const out = [...r1Order];
  for (const s of R1_SENDERS) {
    if (!out.includes(s) && String(r1Body(s, claudeR1, geminiR1, gptR1) || "").trim()) {
      out.push(s);
    }
  }
  return out;
}

function buildTranscriptDict(sessionConfig, prompt, claudeR1, geminiR1, gptR1, synthesisText, r1Order) {
  const order = mergedR1Order(r1Order, claudeR1, geminiR1, gptR1);
  const messages = [
    { role: "user", sender: "You", content: prompt, timestamp: timestamp() },
    ...order.map((sender) => ({
      role: "assistant",
      sender,
      content: r1Body(sender, claudeR1, geminiR1, gptR1),
      round: "round1",
      timestamp: timestamp(),
    })),
    {
      role: "assistant",
      sender: "Claude",
      content: synthesisText,
      round: "synthesis",
      timestamp: timestamp(),
    },
  ];
  return {
    messages,
    session_config: sessionConfig,
    intake_summary: sessionConfig?.intake_summary ?? null,
  };
}

function orderFromResumeMessages(msgs) {
  const order = [];
  if (!Array.isArray(msgs)) return order;
  for (const m of msgs) {
    if (m.role !== "assistant" || m.round !== "round1") continue;
    if (!R1_SENDERS.includes(m.sender)) continue;
    if (!order.includes(m.sender)) order.push(m.sender);
  }
  return order;
}

function downloadJsonFile(payload, filename) {
  const blob = new Blob([JSON.stringify(payload, null, 2)], { type: "application/json" });
  const url = URL.createObjectURL(blob);
  const a = document.createElement("a");
  a.href = url;
  a.download = filename;
  document.body.appendChild(a);
  a.click();
  a.remove();
  URL.revokeObjectURL(url);
}

function formatTierBadge(tier) {
  const raw = (tier || "smart").toString().toLowerCase().replace(/-/g, "_");
  if (raw === "deep_thinking" || raw === "deep") return "Deep";
  if (raw === "quick") return "Quick";
  return "Smart";
}

/** Shown when model_complete arrived but no tokens were received (typical: dropped connection). */
function bubbleBody(text, modelComplete) {
  if (modelComplete && !(text || "").trim()) {
    return "Response interrupted — connection lost";
  }
  return text;
}

/**
 * @param {Object} props
 * @param {Object} props.sessionConfig
 * @param {Object | null} [props.resumeTranscript] — saved `{ messages, intake_summary? }`; skips WebSocket and shows static session + export
 * @param {function} [props.onSynthesisComplete] — (synthesisMarkdown: string) => void
 * @param {function} [props.onNavigateHome] — return to landing (optional)
 */
function SessionView({ sessionConfig, resumeTranscript = null, onSynthesisComplete, onNavigateHome }) {
  const onSynthesisCompleteRef = useRef(onSynthesisComplete);
  useEffect(() => {
    onSynthesisCompleteRef.current = onSynthesisComplete;
  }, [onSynthesisComplete]);

  /** Missing prompt / config — shown above transcript only. */
  const [configError, setConfigError] = useState(null);
  /** Initial connect failure or abnormal close mid-session — shown inline after model bubbles. */
  const [transportError, setTransportError] = useState(null);
  const [streamError, setStreamError] = useState(null);

  const [claudeR1, setClaudeR1] = useState("");
  const [geminiR1, setGeminiR1] = useState("");
  const [gptR1, setGptR1] = useState("");

  const [claudeR1Complete, setClaudeR1Complete] = useState(false);
  const [geminiR1Complete, setGeminiR1Complete] = useState(false);
  const [gptR1Complete, setGptR1Complete] = useState(false);

  const [synthesisText, setSynthesisText] = useState("");
  const [synthesisStreaming, setSynthesisStreaming] = useState(false);
  const [synthesisFinal, setSynthesisFinal] = useState(false);

  const [sessionComplete, setSessionComplete] = useState(false);

  /** First-token arrival order for Round 1 bubbles (Gemini | GPT | Claude). */
  const [r1Order, setR1Order] = useState(/** @type {string[]} */ ([]));
  /** Mirrors server streaming phase for correct “who is typing” indicators. */
  const [streamPhase, setStreamPhase] = useState(/** @type {StreamPhase} */ ("gemini_r1"));
  /** null | 'home' | 'save-exit' */
  const [leaveIntent, setLeaveIntent] = useState(null);

  const r1OrderRef = useRef(/** @type {string[]} */ ([]));
  const r1CountsRef = useRef({ Gemini: 0, GPT: 0, Claude: 0 });

  const ensureR1Order = useCallback((name) => {
    if (r1OrderRef.current.includes(name)) return;
    r1OrderRef.current = [...r1OrderRef.current, name];
    setR1Order([...r1OrderRef.current]);
  }, []);

  const phaseRef = useRef(/** @type {StreamPhase} */ ("gemini_r1"));

  const displayPrompt = useMemo(() => {
    const fromConfig = sessionConfig?.optimized_prompt?.trim();
    if (fromConfig) return sessionConfig.optimized_prompt;
    const u = resumeTranscript?.messages?.find((m) => m.role === "user");
    return u?.content || "";
  }, [sessionConfig, resumeTranscript]);

  const transcriptForExport = useMemo(() => {
    if (resumeTranscript?.messages?.length) {
      return {
        messages: resumeTranscript.messages,
        session_config: sessionConfig,
        intake_summary: resumeTranscript.intake_summary ?? sessionConfig?.intake_summary ?? null,
      };
    }
    return buildTranscriptDict(sessionConfig, displayPrompt, claudeR1, geminiR1, gptR1, synthesisText, r1Order);
  }, [resumeTranscript, sessionConfig, displayPrompt, claudeR1, geminiR1, gptR1, synthesisText, r1Order]);

  const appendToken = useCallback(
    (sender, token) => {
      const phase = phaseRef.current;
      if (!token) return;

      if (phase === "gemini_r1" && sender === "Gemini") {
        const prevLen = r1CountsRef.current.Gemini;
        r1CountsRef.current.Gemini += token.length;
        if (prevLen === 0) ensureR1Order("Gemini");
        setGeminiR1((prev) => prev + token);
        return;
      }
      if (phase === "gpt_r1" && sender === "GPT") {
        const prevLen = r1CountsRef.current.GPT;
        r1CountsRef.current.GPT += token.length;
        if (prevLen === 0) ensureR1Order("GPT");
        setGptR1((prev) => prev + token);
        return;
      }
      if (phase === "claude_r1" && sender === "Claude") {
        const prevLen = r1CountsRef.current.Claude;
        r1CountsRef.current.Claude += token.length;
        if (prevLen === 0) ensureR1Order("Claude");
        setClaudeR1((prev) => prev + token);
        return;
      }
      if (phase === "synthesis" && sender === "Claude") {
        setSynthesisText((prev) => prev + token);
        setSynthesisStreaming(true);
      }
    },
    [ensureR1Order]
  );

  const handleModelComplete = useCallback(
    (sender) => {
      if (phaseRef.current === "gemini_r1" && sender === "Gemini") {
        ensureR1Order("Gemini");
        setGeminiR1Complete(true);
        phaseRef.current = "gpt_r1";
        setStreamPhase("gpt_r1");
        return;
      }
      if (phaseRef.current === "gpt_r1" && sender === "GPT") {
        ensureR1Order("GPT");
        setGptR1Complete(true);
        phaseRef.current = "claude_r1";
        setStreamPhase("claude_r1");
        return;
      }
      if (phaseRef.current === "claude_r1" && sender === "Claude") {
        ensureR1Order("Claude");
        setClaudeR1Complete(true);
        phaseRef.current = "synthesis";
        setStreamPhase("synthesis");
      }
    },
    [ensureR1Order]
  );

  useEffect(() => {
    const msgs = resumeTranscript?.messages;
    if (!msgs?.length || !sessionConfig) return;
    let cl = "";
    let ge = "";
    let gp = "";
    let syn = "";
    for (const m of msgs) {
      if (m.role !== "assistant") continue;
      const r = m.round;
      const s = m.sender;
      if (r === "round1") {
        if (s === "Claude") cl = m.content ?? "";
        if (s === "Gemini") ge = m.content ?? "";
        if (s === "GPT") gp = m.content ?? "";
      }
      if (r === "synthesis" && s === "Claude") syn = m.content ?? "";
    }
    setConfigError(null);
    setTransportError(null);
    setStreamError(null);
    setClaudeR1(cl);
    setGeminiR1(ge);
    setGptR1(gp);
    setClaudeR1Complete(true);
    setGeminiR1Complete(true);
    setGptR1Complete(true);
    setSynthesisText(syn);
    setSynthesisStreaming(false);
    setSynthesisFinal(!!String(syn).trim());
    setSessionComplete(true);
    phaseRef.current = "idle";
    setStreamPhase("idle");
    const ro = orderFromResumeMessages(msgs);
    r1OrderRef.current = ro;
    setR1Order(ro);
    r1CountsRef.current = {
      Gemini: ge.length,
      GPT: gp.length,
      Claude: cl.length,
    };
  }, [resumeTranscript, sessionConfig]);

  useEffect(() => {
    if (resumeTranscript?.messages?.length) {
      return undefined;
    }
    if (!sessionConfig || typeof displayPrompt !== "string" || !displayPrompt.trim()) {
      setConfigError("Missing session configuration or optimized prompt.");
      return undefined;
    }

    let cancelled = false;
    const openedRef = { current: false };
    const completedNormallyRef = { current: false };

    phaseRef.current = "gemini_r1";
    setStreamPhase("gemini_r1");
    r1OrderRef.current = [];
    r1CountsRef.current = { Gemini: 0, GPT: 0, Claude: 0 };
    setR1Order([]);
    setConfigError(null);
    setTransportError(null);
    setStreamError(null);
    setClaudeR1("");
    setGeminiR1("");
    setGptR1("");
    setClaudeR1Complete(false);
    setGeminiR1Complete(false);
    setGptR1Complete(false);
    setSynthesisText("");
    setSynthesisStreaming(false);
    setSynthesisFinal(false);
    setSessionComplete(false);

    const url = wsUrlFromApiBase();
    const ws = new WebSocket(url);

    let pingIntervalId = 0;

    const connectTimeoutId = window.setTimeout(() => {
      if (cancelled) return;
      if (ws.readyState !== WebSocket.OPEN) {
        try {
          ws.close();
        } catch {
          /* ignore */
        }
        setTransportError("Could not connect — timed out waiting for the server.");
      }
    }, WS_CONNECT_TIMEOUT_MS);

    ws.onmessage = (event) => {
      let data;
      try {
        data = JSON.parse(event.data);
      } catch {
        return;
      }

      switch (data.type) {
        case "ping":
        case "pong":
          break;
        case "token":
          appendToken(data.sender, data.token);
          break;
        case "model_complete":
          handleModelComplete(data.sender);
          break;
        case "synthesis_complete":
          setSynthesisText(data.content ?? "");
          setSynthesisStreaming(false);
          setSynthesisFinal(true);
          phaseRef.current = "idle";
          onSynthesisCompleteRef.current?.(data.content ?? "");
          break;
        case "session_complete":
          completedNormallyRef.current = true;
          setSessionComplete(true);
          break;
        case "error":
          setStreamError(data.message || "Session error");
          break;
        default:
          break;
      }
    };

    ws.onopen = () => {
      openedRef.current = true;
      window.clearTimeout(connectTimeoutId);
      ws.send(
        JSON.stringify({
          session_config: sessionConfig,
          prompt: displayPrompt,
          history: [],
        })
      );
      pingIntervalId = window.setInterval(() => {
        if (cancelled || ws.readyState !== WebSocket.OPEN) return;
        try {
          ws.send(JSON.stringify({ type: "ping", t: Date.now() }));
        } catch {
          /* ignore */
        }
      }, WS_KEEPALIVE_INTERVAL_MS);
    };

    ws.onerror = () => {
      /* Browser gives no details; onclose handles messaging. */
    };

    ws.onclose = () => {
      window.clearTimeout(connectTimeoutId);
      if (pingIntervalId) window.clearInterval(pingIntervalId);
      if (cancelled || completedNormallyRef.current) return;
      if (!openedRef.current) {
        setTransportError((prev) => prev || "WebSocket connection failed.");
      } else {
        setTransportError("Session disconnected — responses may be incomplete.");
      }
    };

    return () => {
      cancelled = true;
      window.clearTimeout(connectTimeoutId);
      if (pingIntervalId) window.clearInterval(pingIntervalId);
      ws.onmessage = null;
      ws.onclose = null;
      if (ws.readyState === WebSocket.OPEN || ws.readyState === WebSocket.CONNECTING) {
        ws.close();
      }
    };
  }, [sessionConfig, displayPrompt, resumeTranscript, appendToken, handleModelComplete]);

  const claudeR1Streaming = !claudeR1Complete;
  const geminiR1Streaming = claudeR1Complete && !geminiR1Complete;
  const gptR1Streaming = geminiR1Complete && !gptR1Complete;

  const showGeminiBubble = claudeR1Complete || geminiR1.length > 0;
  const showGptBubble = geminiR1Complete || gptR1.length > 0;

  const inlineAlert = streamError || transportError;
  const synthesisBody =
    synthesisFinal && !synthesisText.trim()
      ? "Response interrupted — connection lost"
      : synthesisText;

  return (
    <div className="min-h-screen bg-bg text-text-primary">
      <header className="border-b border-border px-4 py-4 sm:px-6">
        <div className="mx-auto max-w-3xl">
          <h1 className="text-lg font-semibold">Roundtable</h1>
          {sessionConfig?.session_title && (
            <p className="mt-0.5 text-sm text-text-secondary">{sessionConfig.session_title}</p>
          )}
        </div>
      </header>

      <div className="mx-auto max-w-3xl space-y-6 px-4 py-6 sm:px-6">
        {configError && (
          <p className="text-sm text-red-400" role="alert">
            {configError}
          </p>
        )}

        <section aria-label="Session prompt">
          <h2 className="mb-2 text-xs font-semibold uppercase tracking-wide text-text-secondary">
            Your prompt
          </h2>
          <div className="rounded-lg border border-border bg-surface px-4 py-3 text-sm leading-relaxed text-text-primary whitespace-pre-wrap">
            {displayPrompt || "—"}
          </div>
        </section>

        <section aria-label="Model responses" className="space-y-4">
          <h2 className="text-xs font-semibold uppercase tracking-wide text-text-secondary">
            Transcript
          </h2>

          <ModelBubble
            sender="Claude"
            content={bubbleBody(claudeR1, claudeR1Complete)}
            isStreaming={claudeR1Streaming}
            round="round1"
            complete={claudeR1Complete}
          />

          {showGeminiBubble && (
            <ModelBubble
              sender="Gemini"
              content={bubbleBody(geminiR1, geminiR1Complete)}
              isStreaming={geminiR1Streaming}
              round="round1"
              complete={geminiR1Complete}
            />
          )}

          {showGptBubble && (
            <ModelBubble
              sender="GPT"
              content={bubbleBody(gptR1, gptR1Complete)}
              isStreaming={gptR1Streaming}
              round="round1"
              complete={gptR1Complete}
            />
          )}

          {inlineAlert && (
            <p
              className="max-w-[min(100%,40rem)] rounded-lg border border-red-900/50 bg-surface px-4 py-3 text-sm text-red-400"
              role="alert"
            >
              {inlineAlert}
            </p>
          )}

          {gptR1Complete && (
            <div
              className="max-w-[min(100%,40rem)] rounded-lg border border-border bg-surface px-4 py-3 border-l-4 border-l-perplexity"
              aria-label="Perplexity audit seat"
            >
              <div
                className="mb-2 text-xs font-semibold uppercase tracking-wide"
                style={{ color: MODEL_HEX.Perplexity }}
              >
                Perplexity
                <span className="font-normal normal-case text-text-secondary"> · fact-check</span>
              </div>
              <p className="text-sm leading-relaxed text-text-secondary">
                Live audit stream is not wired in v2 WebSocket sessions; findings are still folded into
                synthesis on the server. v2.1 will stream the audit here (True Turquoise accent).
              </p>
            </div>
          )}
        </section>

        {(synthesisStreaming || synthesisFinal || synthesisText.length > 0) && (
          <SynthesisPanel
            content={synthesisBody}
            isStreaming={synthesisStreaming && !synthesisFinal}
            complete={synthesisFinal}
          />
        )}

        {sessionComplete && (
          <TakeFurther sessionConfig={sessionConfig} transcript={transcriptForExport} />
        )}
      </div>
    </div>
  );
}

export default SessionView;
